INSERT INTO email_templates (internal_name, name, subject, body_html, is_active)
VALUES 
('meeting_reminder_12h', 'Przypomnienie o spotkaniu (12h)', '🔔 Spotkanie dziś: {{temat}} o {{godzina_spotkania}}', 
'<div style="background-color: #ffc105; padding: 20px; text-align: center;"><img src="https://xzlhssqqbajqhnsmbucf.supabase.co/storage/v1/object/public/training-media/1766508615455-8wv0cee7jwr.png" alt="Pure Life Center" style="max-height: 50px; margin-bottom: 10px;" /><h1 style="color: #ffffff; margin: 0; font-size: 24px;">Przypomnienie o spotkaniu</h1></div><div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;"><h2 style="color: #1a365d;">📅 Spotkanie dziś za 12 godzin</h2><p>Cześć {{imię}},</p><p>Przypominamy o zaplanowanym na dziś spotkaniu <strong>{{temat}}</strong>.</p><p>📅 <strong>{{data_spotkania}}</strong> o godzinie <strong>{{godzina_spotkania}}</strong></p><p>👤 Spotkanie z: <strong>{{druga_strona}}</strong></p><p style="color: #666; font-size: 14px;">Upewnij się, że masz wszystko przygotowane. Link do spotkania otrzymasz w kolejnym przypomnieniu.</p></div>', true),
('meeting_reminder_2h', 'Przypomnienie o spotkaniu (2h)', '⏰ Spotkanie za 2 godziny: {{temat}} o {{godzina_spotkania}}', 
'<div style="background-color: #ffc105; padding: 20px; text-align: center;"><img src="https://xzlhssqqbajqhnsmbucf.supabase.co/storage/v1/object/public/training-media/1766508615455-8wv0cee7jwr.png" alt="Pure Life Center" style="max-height: 50px; margin-bottom: 10px;" /><h1 style="color: #ffffff; margin: 0; font-size: 24px;">Przypomnienie o spotkaniu</h1></div><div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;"><h2 style="color: #1a365d;">⏰ Spotkanie za 2 godziny!</h2><p>Cześć {{imię}},</p><p>Twoje spotkanie <strong>{{temat}}</strong> rozpocznie się za 2 godziny.</p><p>📅 <strong>{{data_spotkania}}</strong> o godzinie <strong>{{godzina_spotkania}}</strong></p><p>👤 Spotkanie z: <strong>{{druga_strona}}</strong></p><div style="text-align: center; margin: 24px 0;"><a href="{{zoom_link}}" style="background-color: #2563eb; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-weight: bold;">Dołącz do spotkania</a></div><p style="color: #666; font-size: 14px;">Pokój spotkania będzie otwarty 5 minut przed czasem.</p><p style="color: #666; font-size: 14px;">Jeśli link nie działa, skopiuj i wklej ten adres do przeglądarki:<br>{{zoom_link}}</p></div>', true)
ON CONFLICT (internal_name) DO NOTHING;